sys_script.script:
(function executeRule(current, previous /*null when async*/) {
	function checkIfNameExists(name, count){


		var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');
		gr.addQuery('template_name', name);
		gr.addQuery('process_level', current.process_level);

		if(current.process_level == 'ou_process')
		gr.addQuery('process_ou', current.process_ou);

		gr.query();

		if(gr.next()){
			return true;
		}else{
			return false;
		}


	}
	if((current.template_name != previous.template_name || current.process_level!= previous.process_level || current.process_ou!= previous.process_ou ) && checkIfNameExists(current.template_name)){
		gs.addErrorMessage("The name '" + current.template_name + "' is already being used.  Please change the Template Name to a unique name");
		current.setAbortAction(true);
	}
	var ou_process = '';
	if(current.process_level == "ou_process"){
		ou_process = ' (' + current.process_ou.getDisplayValue() + ') ';
	}
	current.u_process_id = current.template_name + " - " + current.process_level.getDisplayValue()+ ou_process + ' - ' + current.process_owner.getDisplayValue();
	// Add your code here

})(current, previous);
